INSERT INTO TWORK_INFO_IB_HD
(
	CTKEY
	, OWKEY
	, IBHDKEY
	, IBHDTYPECD
	, IBHDDATE
	, IBEXPCTDATE
	, ACKEY
	, ACNM
	, IBCNFRMDATE
	, IBDDLNDATE
