UPDATE TWORK_INTF_IB_HD_RCV
   SET PRCSYN = 'Y'
	 , PRCSDATE = #{sysdate}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORHDKEY = #{orhdkey}

UPDATE TWORK_INTF_IB_DT_RCV
